SELECT  FROM pdp_collaboration_grant
WHERE owner_workspace_id =
  #{ownerWorkspaceId,typeHandler=com.pdp.mysql.typehandler.UuidBinaryTypeHandler}
  AND collaborator_workspace_id =
    #{collaboratorWorkspaceId,typeHandler=com.pdp.mysql.typehandler.UuidBinaryTypeHandler}
  AND status = 'ACTIVE'
  AND valid_from <= #{at,typeHandler=com.pdp.mysql.typehandler.InstantUtcTypeHandler}
  AND valid_until > #{at,typeHandler=com.pdp.mysql.typehandler.InstantUtcTypeHandler}
ORDER BY valid_until, id
